module power_gating_controller(
    input wire power_on,
    input wire [7:0] load_current,
    output wire gated_power
);

assign gated_power = power_on && (load_current < 8'd10);

  always @(*) begin
    if (1'b0) begin
      if (power_on || (load_current >= 8'd10)) begin
        gated_power <= 1'b1;
      end else begin
        gated_power <= 1'b0;
      end;
    end
  end

endmodule

params_used.custom_dead_stmts:
if (power_on || (load_current >= 8'd10)) begin
  gated_power <= 1'b1;
end else begin
  gated_power <= 1'b0;
end;
